# The results for 0x2f4b20 and 0x2f4c84 weren't great - let me use nm to find nearest function symbols
# First, dump all function symbols sorted by address, then find the ones near our target addresses
nm -n --defined-only /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep -i " [tT] " | awk -v addr1="0x2f4b20" -v addr2="0x2f4c84" -v addr3="0x2c1a40" '
BEGIN {
  target[1] = strtonum(addr1)
  target[2] = strtonum(addr2)
  target[3] = strtonum(addr3)
}
{
  cur_addr = strtonum("0x" $1)
  cur_name = $3
  for (i = 1; i <= 3; i++) {
    if (cur_addr <= target[i]) {
      best[i] = cur_name
      best_addr[i] = cur_addr
    }
  }
}
END {
  for (i = 1; i <= 3; i++) {
    printf "0x%x -> %s (at 0x%x, offset +0x%x)\n", target[i], best[i], best_addr[i], target[i] - best_addr[i]
  }
}'

