arguments.command:
# Let me get all symbols (including DWARF debug info symbols) sorted by address
# and find the closest function for each address
nm -C -n --defined-only /tmp/symbols/libmonosgen-2.0.so.dbg 2>/dev/null | grep " [tTwW] " | awk '
{
  addr = strtonum("0x" $1)
  name = $3
  for (i = 4; i <= NF; i++) name = name " " $i
  addrs[NR] = addr
  names[NR] = name
  total = NR
}
END {
  split("0x2f4b20 0x2f4c84 0x2c1a40", targets, " ")
  for (t in targets) {
    taddr = strtonum(targets[t])
    best_name = "??"
    best_addr = 0
    for (i = 1; i <= total; i++) {
      if (addrs[i] <= taddr && addrs[i] > best_addr) {
        # Skip $d and $x markers
        if (substr(names[i], 1, 2) != "$d" && substr(names[i], 1, 2) != "$x" && substr(names[i], 1, 15) != "__CortexA53843") {
          best_addr = addrs[i]
          best_name = names[i]
        }
      }
    }
    printf "%s -> %s (base 0x%x, offset +0x%x)\n", targets[t], best_name, best_addr, taddr - best_addr
  }
}' 2>&1

